INSERT INTO `faqs` (`id`, `question`, `answer`, `created_at`) VALUES
(1, 'Bagaimana cara membatalkan reservasi?', 'Anda dapat membatalkan reservasi paling lambat 2 jam sebelum jadwal dimulai melalui menu Riwayat Transaksi. Biaya pembayaran Anda akan dikembalikan sesuai ketentuan yang berlaku', '2026-06-21 10:30:54'),
(2, 'Bagaimana cara menggunakan Poin Elite?', 'Poin Elite dapat ditukarkan secara otomatis saat Anda melakukan pembayaran. Anda bisa memotong total biaya layanan menggunakan akumulasi poin yang Anda miliki.', '2026-06-21 10:30:54'),
(3, 'Apakah saya bisa datang terlambat?', 'Toleransi keterlambatan adalah 15 menit dari jadwal reservasi. Lebih dari itu, barber berhak melayani pelanggan berikutnya dan Anda akan dijadwalkan ulang sesuai ketersediaan.', '2026-06-21 10:30:54'),
(4, 'Metode pembayaran apa saja yang tersedia?', 'Kami menerima pembayaran Tunai, QRIS, Transfer Bank (BCA, Mandiri), dan E-Wallet (GoPay, OVO, Dana).', '2026-06-21 10:30:54');

